-- ============================================================
-- MAP A (Design Map) - Full SQL Schema & Seed Data
-- ============================================================
-- This file creates the complete Map A database:
--   - design_map_stalls: All stalls for Map A
--   - design_map_reservations: Reservation records for Map A
-- ============================================================

DROP TABLE IF EXISTS design_map_reservations;
DROP TABLE IF EXISTS design_map_stalls;

-- ─────────────────────────────────────────────────────────────
-- Table: design_map_stalls
-- ─────────────────────────────────────────────────────────────
CREATE TABLE design_map_stalls (
  id VARCHAR(8) NOT NULL,
  section VARCHAR(32) NOT NULL,
  number INT NOT NULL DEFAULT 0,
  status VARCHAR(16) NOT NULL DEFAULT 'available',
  price INT NOT NULL DEFAULT 0,
  size VARCHAR(16) NOT NULL DEFAULT 'medium',
  category VARCHAR(64) NOT NULL DEFAULT '',
  description TEXT,
  image_url TEXT,
  reservation_id VARCHAR(64) DEFAULT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  KEY idx_dms_status (status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ─────────────────────────────────────────────────────────────
-- Table: design_map_reservations
-- ─────────────────────────────────────────────────────────────
CREATE TABLE design_map_reservations (
  id VARCHAR(64) NOT NULL,
  reservation_number VARCHAR(32) NOT NULL,
  stall_id VARCHAR(8) NOT NULL,
  full_name VARCHAR(128) NOT NULL,
  contact_number VARCHAR(32) NOT NULL,
  business_name VARCHAR(128) DEFAULT NULL,
  dti_number VARCHAR(64) DEFAULT NULL,
  cedula_number VARCHAR(64) DEFAULT NULL,
  address TEXT DEFAULT NULL,
  stall_usage_type VARCHAR(64) DEFAULT NULL,
  status VARCHAR(16) NOT NULL DEFAULT 'pending',
  admin_notes TEXT DEFAULT NULL,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  expires_at TIMESTAMP NULL DEFAULT NULL,
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uk_dmr_reservation_number (reservation_number),
  KEY idx_dmr_stall (stall_id),
  KEY idx_dmr_status (status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

